         Value *NewOr = Builder.CreateOr(Z, ~(*C2));
         return Builder.CreateSub(RHS, NewOr, "sub");
       }
+  // Removed misplaced min pattern
+  // umin(X + 1, Y) - umin(X, Y) --> X <u Y ? 1 : 0
+  Value *X0, *Y0, *X1, *Y1;
+  const APInt *C;
+  if (MinMax->isSigned()) {
+    if (match(Op1, m_OneUse(m_SMin(m_Value(X0), m_Value(Y0)))) &&
+        match(Op0, m_OneUse(m_SMin(m_c_Add(m_Value(X1), m_ConstantInt(C)),
+                                   m_Value(Y1)))) &&
+        X0 == X1 && Y0 == Y1 && C->isOne()) {
+      Value *Cmp = Builder.CreateICmpSLT(X0, Y0);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+  } else {
+    if (match(Op1, m_OneUse(m_UMin(m_Value(X0), m_Value(Y0)))) &&
+        match(Op0, m_OneUse(m_UMin(m_c_Add(m_Value(X1), m_ConstantInt(C)),
+                                   m_Value(Y1)))) &&
+        X0 == X1 && Y0 == Y1 && C->isOne()) {
+      Value *Cmp = Builder.CreateICmpULT(X0, Y0);
+      return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                                ConstantInt::get(Ty, 0));
+    }
+  }
+
   return nullptr;
 }

